fn eval_runtime_index_value(
    base: RuntimeValue,
    index: RuntimeValue,
    scopes: &mut Vec<RuntimeScope>,
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> Result<RuntimeValue, String> {
    let base = read_runtime_value_if_ref(
        base,
        scopes,
        plan,
        current_package_id,
        current_module_id,
        aliases,
        type_bindings,
        state,
        host,
    )?;
    let index = expect_int(index, "index")?;
    match base {
        RuntimeValue::List(values) => {
            let index = runtime_index_to_usize(index, values.len(), "list index")?;
            values
                .get(index)
                .cloned()
                .ok_or_else(|| format!("list index `{index}` is out of bounds"))
        }
        RuntimeValue::Array(values) => {
            let index = runtime_index_to_usize(index, values.len(), "array index")?;
            values
                .get(index)
                .cloned()
                .ok_or_else(|| format!("array index `{index}` is out of bounds"))
        }
        other => Err(format!(
            "runtime index expects List or Array, got `{other:?}`"
        )),
    }
}

fn eval_runtime_slice_value(
    base: RuntimeValue,
    start: Option<RuntimeValue>,
    end: Option<RuntimeValue>,
    inclusive_end: bool,
    scopes: &mut Vec<RuntimeScope>,
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> Result<RuntimeValue, String> {
    let base = read_runtime_value_if_ref(
        base,
        scopes,
        plan,
        current_package_id,
        current_module_id,
        aliases,
        type_bindings,
        state,
        host,
    )?;
    let (values, slice_kind) = match base {
        RuntimeValue::List(values) => (values, "list"),
        RuntimeValue::Array(values) => (values, "array"),
        other => {
            return Err(format!(
                "runtime slice expects List or Array, got `{other:?}`"
            ));
        }
    };
    let len = values.len();
    let start = runtime_slice_bound_to_usize(
        start
            .map(|value| expect_int(value, "slice start"))
            .transpose()?,
        0,
        len,
        "slice",
        "start",
    )?;
    let raw_end = runtime_slice_bound_to_usize(
        end.clone()
            .map(|value| expect_int(value, "slice end"))
            .transpose()?,
        len,
        len,
        "slice",
        "end",
    )?;
    let end = if inclusive_end {
        if end.is_some() {
            if raw_end >= len {
                return Err(format!(
                    "slice inclusive end `{raw_end}` is out of bounds for length `{len}`"
                ));
            }
            raw_end + 1
        } else {
            len
        }
    } else {
        raw_end
    };
    if start > end {
        return Err(format!(
            "slice start `{start}` must be less than or equal to end `{end}`"
        ));
    }
    let sliced = values[start..end].to_vec();
    Ok(match slice_kind {
        "list" => RuntimeValue::List(sliced),
        "array" => RuntimeValue::Array(sliced),
        _ => unreachable!("validated runtime slice carrier kind"),
    })
}

fn runtime_slice_window(
    start: Option<i64>,
    end: Option<i64>,
    inclusive_end: bool,
    len: usize,
    context: &str,
) -> Result<(usize, usize), String> {
    let start = runtime_slice_bound_to_usize(start, 0, len, context, "start")?;
    let has_end = end.is_some();
    let raw_end = runtime_slice_bound_to_usize(end, len, len, context, "end")?;
    let end = if inclusive_end {
        if has_end {
            if raw_end >= len {
                return Err(format!(
                    "{context} inclusive end `{raw_end}` is out of bounds for length `{len}`"
                ));
            }
            raw_end + 1
        } else {
            len
        }
    } else {
        raw_end
    };
    if start > end {
        return Err(format!(
            "{context} start `{start}` must be less than or equal to end `{end}`"
        ));
    }
    Ok((start, end))
}

fn eval_runtime_borrowed_slice_view(
    base_expr: &ParsedExpr,
    start: Option<&ParsedExpr>,
    end: Option<&ParsedExpr>,
    inclusive_end: bool,
    mutable: bool,
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> Result<RuntimeValue, String> {
    let borrowed_place = expr_to_assign_target(base_expr)
        .and_then(|target| resolve_assign_target_place(scopes, &target).ok());
    if mutable
        && let Some(place) = &borrowed_place
        && !place.mode.allows_write()
    {
        return Err("runtime mutable borrowed slices require writable backing".to_string());
    }
    let base = read_runtime_value_if_ref(
        eval_expr(
            base_expr,
            plan,
            current_package_id,
            current_module_id,
            scopes,
            aliases,
            type_bindings,
            state,
            host,
        )
        .map_err(runtime_eval_message)?,
        scopes,
        plan,
        current_package_id,
        current_module_id,
        aliases,
        type_bindings,
        state,
        host,
    )?;
    let start = eval_optional_runtime_int_expr(
        start,
        plan,
        current_package_id,
        current_module_id,
        scopes,
        aliases,
        type_bindings,
        state,
        host,
        "borrowed slice start",
    )
    .map_err(runtime_eval_message)?;
    let end = eval_optional_runtime_int_expr(
        end,
        plan,
        current_package_id,
        current_module_id,
        scopes,
        aliases,
        type_bindings,
        state,
        host,
        "borrowed slice end",
    )
    .map_err(runtime_eval_message)?;
    match base {
        RuntimeValue::List(_) => Err(
            "runtime borrowed slices require contiguous backing; `List` is not supported"
                .to_string(),
        ),
        RuntimeValue::Array(values) => {
            let (start, end) =
                runtime_slice_window(start, end, inclusive_end, values.len(), "borrowed slice")?;
            let len = end - start;
            if let Some(place) = borrowed_place {
                if let RuntimeReferenceTarget::Local { local, .. } = &place.target
                    && let Some((_, runtime_local)) =
                        lookup_local_with_name_by_handle(scopes, *local)
                {
                    state
                        .captured_local_values
                        .entry(*local)
                        .or_insert_with(|| runtime_local.value.clone());
                }
                let reference = RuntimeReferenceValue {
                    mode: place.mode,
                    target: place.target,
                };
                if mutable {
                    runtime_reject_live_reference_or_opaque_conflict(
                        Some(scopes.as_slice()),
                        None,
                        state,
                        |candidate| candidate.target == reference.target,
                        |opaque, state| runtime_opaque_matches_reference_predicate(
                            opaque,
                            state,
                            &|candidate| candidate.target == reference.target,
                        ),
                        None,
                        None,
                        |_| false,
                        "runtime mutable borrowed slices require exclusive view access while conflicting borrows or views are live".to_string(),
                    )?;
                    let handle =
                        insert_runtime_edit_view_from_reference(state, &[], reference, start, len);
                    Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::EditView(handle)))
                } else {
                    let handle =
                        insert_runtime_read_view_from_reference(state, &[], reference, start, len);
                    Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::ReadView(handle)))
                }
            } else if mutable {
                let handle = insert_runtime_edit_view(state, &[], values[start..end].to_vec());
                Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::EditView(handle)))
            } else {
                let handle = insert_runtime_read_view(state, &[], values[start..end].to_vec());
                Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::ReadView(handle)))
            }
        }
        RuntimeValue::Str(text) => {
            if mutable {
                return Err(
                    "runtime string slices are read-only; `&edit x[a..b]` is not allowed"
                        .to_string(),
                );
            }
            let (start, end) =
                runtime_slice_window(start, end, inclusive_end, text.len(), "borrowed slice")?;
            let handle = {
                let backing = insert_runtime_str_view_buffer(state, text);
                insert_runtime_str_view_from_buffer(state, backing, start, end - start)
            };
            Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::StrView(handle)))
        }
        RuntimeValue::Opaque(RuntimeOpaqueValue::ReadView(handle)) => {
            if mutable {
                return Err("runtime mutable borrowed slices require editable backing".to_string());
            }
            let (type_args, backing, view_start, view_len) = {
                let view = state
                    .read_views
                    .get(&handle)
                    .ok_or_else(|| format!("invalid ReadView handle `{}`", handle.0))?;
                (
                    view.type_args.clone(),
                    view.backing.clone(),
                    view.start,
                    view.len,
                )
            };
            let (start, end) =
                runtime_slice_window(start, end, inclusive_end, view_len, "borrowed slice")?;
            let next = insert_runtime_read_view_from_backing(
                state,
                &type_args,
                backing,
                view_start + start,
                end - start,
            );
            Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::ReadView(next)))
        }
        RuntimeValue::Opaque(RuntimeOpaqueValue::EditView(handle)) => {
            let (type_args, backing, view_start, view_len) = {
                let view = state
                    .edit_views
                    .get(&handle)
                    .ok_or_else(|| format!("invalid EditView handle `{}`", handle.0))?;
                (
                    view.type_args.clone(),
                    view.backing.clone(),
                    view.start,
                    view.len,
                )
            };
            let (start, end) =
                runtime_slice_window(start, end, inclusive_end, view_len, "borrowed slice")?;
            if mutable {
                let next = match backing {
                    RuntimeElementViewBacking::Buffer(buffer) => {
                        runtime_reject_live_reference_or_opaque_conflict(
                            Some(scopes.as_slice()),
                            None,
                            state,
                            |_| false,
                            |opaque, state| {
                                runtime_opaque_matches_element_buffer(opaque, state, buffer)
                            },
                            None,
                            Some(RuntimeOpaqueValue::EditView(handle)),
                            |_| false,
                            "runtime mutable borrowed slices require exclusive view access while conflicting borrows or views are live".to_string(),
                        )?;
                        insert_runtime_edit_view_from_buffer(
                            state,
                            &type_args,
                            buffer,
                            view_start + start,
                            end - start,
                        )
                    }
                    RuntimeElementViewBacking::Reference(reference) => {
                        runtime_reject_live_reference_or_opaque_conflict(
                            Some(scopes.as_slice()),
                            None,
                            state,
                            |candidate| candidate.target == reference.target,
                            |opaque, state| runtime_opaque_matches_reference_predicate(
                                opaque,
                                state,
                                &|candidate| candidate.target == reference.target,
                            ),
                            None,
                            Some(RuntimeOpaqueValue::EditView(handle)),
                            |_| false,
                            "runtime mutable borrowed slices require exclusive view access while conflicting borrows or views are live".to_string(),
                        )?;
                        insert_runtime_edit_view_from_reference(
                            state,
                            &type_args,
                            reference,
                            view_start + start,
                            end - start,
                        )
                    }
                    RuntimeElementViewBacking::RingWindow { arena, slots } => {
                        let active = runtime_ring_window_active_slots(
                            &slots,
                            view_start + start,
                            end - start,
                        )
                        .ok_or_else(|| {
                            "runtime mutable borrowed slice range is out of bounds for ring window"
                                .to_string()
                        })?
                        .to_vec();
                        let ids = runtime_ring_ids_for_slots(state, arena, &active)?;
                        runtime_reject_live_reference_or_opaque_conflict(
                            Some(scopes.as_slice()),
                            None,
                            state,
                            |candidate| ids.iter().any(|id| runtime_reference_targets_ring_id(candidate, *id)),
                            |opaque, state| runtime_opaque_matches_ring_window_predicate(
                                opaque,
                                state,
                                &|candidate_arena, candidate_slots| {
                                    runtime_ring_window_overlaps_slots(
                                        arena,
                                        &active,
                                        candidate_arena,
                                        candidate_slots,
                                    )
                                },
                            ),
                            None,
                            Some(RuntimeOpaqueValue::EditView(handle)),
                            |_| false,
                            "runtime mutable borrowed slices require exclusive view access while conflicting borrows or views are live".to_string(),
                        )?;
                        insert_runtime_edit_view_from_ring_window(
                            state,
                            &type_args,
                            arena,
                            slots,
                            view_start + start,
                            end - start,
                        )
                    }
                };
                Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::EditView(next)))
            } else {
                let next = insert_runtime_read_view_from_backing(
                    state,
                    &type_args,
                    backing,
                    view_start + start,
                    end - start,
                );
                Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::ReadView(next)))
            }
        }
        RuntimeValue::Opaque(RuntimeOpaqueValue::ByteView(handle)) => {
            if mutable {
                return Err("runtime mutable borrowed slices require editable backing".to_string());
            }
            let view = state
                .byte_views
                .get(&handle)
                .ok_or_else(|| format!("invalid ByteView handle `{}`", handle.0))?
                .clone();
            let (start, end) =
                runtime_slice_window(start, end, inclusive_end, view.len, "borrowed slice")?;
            let next = match view.backing {
                RuntimeByteViewBacking::Buffer(buffer) => insert_runtime_byte_view_from_buffer(
                    state,
                    buffer,
                    view.start + start,
                    end - start,
                ),
                RuntimeByteViewBacking::Reference(reference) => {
                    insert_runtime_byte_view_from_reference(
                        state,
                        reference,
                        view.start + start,
                        end - start,
                    )
                }
            };
            Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::ByteView(next)))
        }
        RuntimeValue::Opaque(RuntimeOpaqueValue::ByteEditView(handle)) => {
            let view = state
                .byte_edit_views
                .get(&handle)
                .ok_or_else(|| format!("invalid ByteEditView handle `{}`", handle.0))?
                .clone();
            let (start, end) =
                runtime_slice_window(start, end, inclusive_end, view.len, "borrowed slice")?;
            if mutable {
                runtime_reject_live_reference_or_opaque_conflict(
                    Some(scopes.as_slice()),
                    None,
                    state,
                    |candidate| match &view.backing {
                        RuntimeByteViewBacking::Buffer(_) => false,
                        RuntimeByteViewBacking::Reference(reference) => {
                            candidate.target == reference.target
                        }
                    },
                    |opaque, state| match &view.backing {
                        RuntimeByteViewBacking::Buffer(buffer) => {
                            runtime_opaque_matches_byte_buffer(opaque, state, *buffer)
                        }
                        RuntimeByteViewBacking::Reference(reference) => {
                            runtime_opaque_matches_reference_predicate(
                                opaque,
                                state,
                                &|candidate| candidate.target == reference.target,
                            )
                        }
                    },
                    None,
                    Some(RuntimeOpaqueValue::ByteEditView(handle)),
                    |_| false,
                    "runtime mutable borrowed slices require exclusive view access while conflicting borrows or views are live".to_string(),
                )?;
                let next = match view.backing {
                    RuntimeByteViewBacking::Buffer(buffer) => {
                        insert_runtime_byte_edit_view_from_buffer(
                            state,
                            buffer,
                            view.start + start,
                            end - start,
                        )
                    }
                    RuntimeByteViewBacking::Reference(reference) => {
                        insert_runtime_byte_edit_view_from_reference(
                            state,
                            reference,
                            view.start + start,
                            end - start,
                        )
                    }
                };
                Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::ByteEditView(next)))
            } else {
                let next = match view.backing {
                    RuntimeByteViewBacking::Buffer(buffer) => insert_runtime_byte_view_from_buffer(
                        state,
                        buffer,
                        view.start + start,
                        end - start,
                    ),
                    RuntimeByteViewBacking::Reference(reference) => {
                        insert_runtime_byte_view_from_reference(
                            state,
                            reference,
                            view.start + start,
                            end - start,
                        )
                    }
                };
                Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::ByteView(next)))
            }
        }
        RuntimeValue::Opaque(RuntimeOpaqueValue::StrView(handle)) => {
            if mutable {
                return Err(
                    "runtime string slices are read-only; `&edit x[a..b]` is not allowed"
                        .to_string(),
                );
            }
            let view = state
                .str_views
                .get(&handle)
                .ok_or_else(|| format!("invalid StrView handle `{}`", handle.0))?
                .clone();
            let (start, end) =
                runtime_slice_window(start, end, inclusive_end, view.len, "borrowed slice")?;
            let next = match view.backing {
                RuntimeStrViewBacking::Buffer(buffer) => insert_runtime_str_view_from_buffer(
                    state,
                    buffer,
                    view.start + start,
                    end - start,
                ),
                RuntimeStrViewBacking::Reference(reference) => {
                    insert_runtime_str_view_from_reference(
                        state,
                        reference,
                        view.start + start,
                        end - start,
                    )
                }
            };
            Ok(RuntimeValue::Opaque(RuntimeOpaqueValue::StrView(next)))
        }
        other => Err(format!(
            "runtime borrowed slice expects contiguous array, view, or string backing, got `{other:?}`"
        )),
    }
}

fn eval_optional_runtime_int_expr(
    expr: Option<&ParsedExpr>,
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
    context: &str,
) -> RuntimeEvalResult<Option<i64>> {
    expr.map(|expr| {
        expect_int(
            eval_expr(
                expr,
                plan,
                current_package_id,
                current_module_id,
                scopes,
                aliases,
                type_bindings,
                state,
                host,
            )?,
            context,
        )
        .map_err(RuntimeEvalSignal::from)
    })
    .transpose()
}

fn eval_match_expr(
    subject: &ParsedExpr,
    arms: &[ParsedMatchArm],
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> RuntimeEvalResult<RuntimeValue> {
    let subject = eval_expr(
        subject,
        plan,
        current_package_id,
        current_module_id,
        scopes,
        aliases,
        type_bindings,
        state,
        host,
    )
    .map_err(runtime_eval_message)?;
    for arm in arms {
        for pattern in &arm.patterns {
            let mut bindings = BTreeMap::new();
            if !match_pattern(pattern, &subject, &mut bindings) {
                continue;
            }
            let mut scope = RuntimeScope::default();
            for (name, value) in bindings {
                insert_runtime_local(state, scopes.len(), &mut scope, 0, name, false, value);
            }
            scopes.push(scope);
            let result = eval_expr(
                &arm.value,
                plan,
                current_package_id,
                current_module_id,
                scopes,
                aliases,
                type_bindings,
                state,
                host,
            );
            scopes.pop();
            return result;
        }
    }
    Err("runtime match expression had no matching arm"
        .to_string()
        .into())
}

fn err_variant(message: String) -> RuntimeValue {
    RuntimeValue::Variant {
        name: "Result.Err".to_string(),
        payload: vec![RuntimeValue::Str(message)],
    }
}

fn expect_cleanup_outcome(value: RuntimeValue) -> Result<(), String> {
    match value {
        RuntimeValue::Unit => Ok(()),
        RuntimeValue::Variant { name, payload } if variant_name_matches(&name, "Result.Ok") => {
            match payload.as_slice() {
                [RuntimeValue::Unit] => Ok(()),
                _ => Err(format!(
                    "cleanup footer expected Result.Ok(Unit), got `{name}`"
                )),
            }
        }
        RuntimeValue::Variant { name, payload } if variant_name_matches(&name, "Result.Err") => {
            match payload.as_slice() {
                [RuntimeValue::Str(message)] => Err(message.clone()),
                [other] => Err(format!(
                    "cleanup footer expected Result.Err(Str), got `{other:?}`"
                )),
                _ => Err(format!(
                    "cleanup footer expected Result.Err(Str), got `{name}`"
                )),
            }
        }
        other => Err(format!(
            "cleanup footer expected Result[Unit, Str], got `{other:?}`"
        )),
    }
}

fn try_construct_record_value(
    callable: &[String],
    resolved_type_args: &[String],
    args: &[ParsedPhraseArg],
    attached: &[ParsedHeaderAttachment],
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> RuntimeEvalResult<Option<RuntimeValue>> {
    if !attached.is_empty() {
        return Ok(None);
    }
    if args.is_empty() {
        return Ok(None);
    }
    let mut fields = BTreeMap::new();
    for arg in args {
        let Some(name) = &arg.name else {
            return Ok(None);
        };
        if fields.contains_key(name) {
            return Err(format!(
                "record constructor `{}` provided duplicate field `{name}`",
                callable.join(".")
            )
            .into());
        }
        fields.insert(
            name.clone(),
            eval_expr(
                &arg.value,
                plan,
                current_package_id,
                current_module_id,
                scopes,
                aliases,
                type_bindings,
                state,
                host,
            )?,
        );
    }
    let name = if resolved_type_args.is_empty() {
        callable.join(".")
    } else {
        format!("{}[{}]", callable.join("."), resolved_type_args.join(", "))
    };
    apply_runtime_struct_bitfield_layout(plan, &name, &mut fields)
        .map_err(RuntimeEvalSignal::from)?;
    Ok(Some(RuntimeValue::Record { name, fields }))
}

fn looks_like_variant_constructor(callable: &[String]) -> bool {
    if callable.len() < 2 {
        return false;
    }
    let Some(enum_name) = callable.get(callable.len().saturating_sub(2)) else {
        return false;
    };
    let Some(variant_name) = callable.last() else {
        return false;
    };
    enum_name.chars().next().is_some_and(char::is_uppercase)
        && variant_name.chars().next().is_some_and(char::is_uppercase)
}

fn try_construct_variant_value(
    callable: &[String],
    args: &[ParsedPhraseArg],
    attached: &[ParsedHeaderAttachment],
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> RuntimeEvalResult<Option<RuntimeValue>> {
    if !looks_like_variant_constructor(callable) || !attached.is_empty() {
        return Ok(None);
    }
    let mut payload = Vec::with_capacity(args.len());
    for arg in args {
        if arg.name.is_some() {
            return Ok(None);
        }
        payload.push(eval_expr(
            &arg.value,
            plan,
            current_package_id,
            current_module_id,
            scopes,
            aliases,
            type_bindings,
            state,
            host,
        )?);
    }
    Ok(Some(RuntimeValue::Variant {
        name: callable.join("."),
        payload,
    }))
}

fn truncate_float_to_int(value: f64, context: &str) -> Result<i64, String> {
    if !value.is_finite() {
        return Err(format!("{context} requires a finite float value"));
    }
    if value < i64::MIN as f64 || value > i64::MAX as f64 {
        return Err(format!(
            "{context} float value `{value}` is out of i64 range"
        ));
    }
    Ok(value.trunc() as i64)
}

fn validate_int_width(value: i64, bits: u32, signed: bool, context: &str) -> Result<i64, String> {
    let valid = if signed {
        let shift = bits.saturating_sub(1);
        let min = -(1_i128 << shift);
        let max = (1_i128 << shift) - 1;
        (value as i128) >= min && (value as i128) <= max
    } else {
        value >= 0 && (value as u128) <= ((1_u128 << bits) - 1)
    };
    if valid {
        Ok(value)
    } else {
        Err(format!(
            "{context} value `{value}` is out of range for {}-bit {} integer",
            bits,
            if signed { "signed" } else { "unsigned" }
        ))
    }
}

fn convert_runtime_numeric_value(
    target: &str,
    value: RuntimeValue,
) -> Result<RuntimeValue, String> {
    match target {
        "F32" => match value {
            RuntimeValue::Int(value) => Ok(make_runtime_float(ParsedFloatKind::F32, value as f64)),
            RuntimeValue::Float { text, kind } => Ok(make_runtime_float(
                ParsedFloatKind::F32,
                parse_runtime_float_text(&text, kind)?,
            )),
            other => Err(format!(
                "F32 conversion expected numeric input, got `{other:?}`"
            )),
        },
        "F64" => match value {
            RuntimeValue::Int(value) => Ok(make_runtime_float(ParsedFloatKind::F64, value as f64)),
            RuntimeValue::Float { text, kind } => Ok(make_runtime_float(
                ParsedFloatKind::F64,
                parse_runtime_float_text(&text, kind)?,
            )),
            other => Err(format!(
                "F64 conversion expected numeric input, got `{other:?}`"
            )),
        },
        "Int" | "I8" | "U8" | "I16" | "U16" | "I32" | "U32" | "I64" | "U64" | "ISize" | "USize" => {
            let context = format!("{target} conversion");
            let int_value = match value {
                RuntimeValue::Int(value) => value,
                RuntimeValue::Float { text, kind } => {
                    truncate_float_to_int(parse_runtime_float_text(&text, kind)?, &context)?
                }
                other => {
                    return Err(format!(
                        "{target} conversion expected numeric input, got `{other:?}`"
                    ));
                }
            };
            let checked = match target {
                "I8" => validate_int_width(int_value, 8, true, &context)?,
                "U8" => validate_int_width(int_value, 8, false, &context)?,
                "I16" => validate_int_width(int_value, 16, true, &context)?,
                "U16" => validate_int_width(int_value, 16, false, &context)?,
                "I32" => validate_int_width(int_value, 32, true, &context)?,
                "U32" => validate_int_width(int_value, 32, false, &context)?,
                "I64" | "ISize" | "Int" => int_value,
                "U64" | "USize" => {
                    if int_value < 0 {
                        return Err(format!(
                            "{context} value `{int_value}` must be non-negative"
                        ));
                    }
                    int_value
                }
                _ => unreachable!(),
            };
            Ok(RuntimeValue::Int(checked))
        }
        _ => Err(format!("unsupported numeric conversion target `{target}`")),
    }
}

fn try_execute_builtin_numeric_conversion(
    callable: &[String],
    args: &[ParsedPhraseArg],
    attached: &[ParsedHeaderAttachment],
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> RuntimeEvalResult<Option<RuntimeValue>> {
    let [target] = callable else {
        return Ok(None);
    };
    if !matches!(
        target.as_str(),
        "Int"
            | "I8"
            | "U8"
            | "I16"
            | "U16"
            | "I32"
            | "U32"
            | "I64"
            | "U64"
            | "ISize"
            | "USize"
            | "F32"
            | "F64"
    ) {
        return Ok(None);
    }
    if !attached.is_empty() {
        return Err(format!("`{target}` conversion does not support attached blocks").into());
    }
    if args.len() != 1 || args[0].name.is_some() {
        return Err(
            format!("`{target}` conversion expects exactly one positional argument").into(),
        );
    }
    let value = eval_expr(
        &args[0].value,
        plan,
        current_package_id,
        current_module_id,
        scopes,
        aliases,
        type_bindings,
        state,
        host,
    )?;
    Ok(Some(
        convert_runtime_numeric_value(target, value).map_err(RuntimeEvalSignal::from)?,
    ))
}

fn try_construct_array_value(
    _callable: &[String],
    args: &[ParsedPhraseArg],
    attached: &[ParsedHeaderAttachment],
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> RuntimeEvalResult<Option<RuntimeValue>> {
    if !attached.is_empty() || args.iter().any(|arg| arg.name.is_some()) {
        return Ok(None);
    }
    let values = args
        .iter()
        .map(|arg| {
            eval_expr(
                &arg.value,
                plan,
                current_package_id,
                current_module_id,
                scopes,
                aliases,
                type_bindings,
                state,
                host,
            )
        })
        .collect::<Result<Vec<_>, _>>()?;
    Ok(Some(RuntimeValue::Array(values)))
}

fn into_iterable_values(value: RuntimeValue) -> Result<Vec<RuntimeValue>, String> {
    match value {
        RuntimeValue::List(values) => Ok(values),
        RuntimeValue::Array(values) => Ok(values),
        RuntimeValue::Map(entries) => Ok(entries
            .into_iter()
            .map(|(key, value)| make_pair(key, value))
            .collect()),
        RuntimeValue::Range {
            start,
            end,
            inclusive_end,
        } => {
            let Some(end) = end else {
                return Err("runtime for-loop range must have an end bound".to_string());
            };
            let start = start.unwrap_or(0);
            let iter = if inclusive_end {
                (start..=end).collect::<Vec<_>>()
            } else {
                (start..end).collect::<Vec<_>>()
            };
            Ok(iter.into_iter().map(RuntimeValue::Int).collect())
        }
        other => Err(format!(
            "runtime for-loop expects List, Array, Map, or RangeInt, got `{other:?}`"
        )),
    }
}

fn resolve_routine_index_for_call(
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    callable: &[String],
    call_args: &[RuntimeCallArg],
    resolved_routine: Option<&str>,
    dynamic_dispatch: Option<&ParsedDynamicDispatch>,
    allow_receiver_root_fallback: bool,
    state: Option<&RuntimeExecutionState>,
) -> Result<Option<usize>, String> {
    let bare_receiver_lookup =
        dynamic_dispatch.is_none() && allow_receiver_root_fallback && callable.len() == 1;
    let candidates = match dynamic_dispatch {
        Some(ParsedDynamicDispatch::TraitMethod { trait_path }) => {
            let Some(method_name) = callable.last() else {
                return Ok(None);
            };
            resolve_dynamic_method_candidate_indices(plan, method_name, trait_path)
        }
        None if bare_receiver_lookup => {
            resolve_method_candidate_indices_by_name(plan, &callable[0])
        }
        None => {
            resolve_routine_candidate_indices(plan, current_package_id, current_module_id, callable)
        }
    };
    if candidates.is_empty() {
        return Ok(None);
    }
    if let Some(routine_key) = resolved_routine {
        let filtered = candidates
            .into_iter()
            .filter(|index| {
                plan.routines
                    .get(*index)
                    .map(|routine| routine.routine_key == routine_key)
                    .unwrap_or(false)
            })
            .collect::<Vec<_>>();
        return match filtered.as_slice() {
            [] => Err(format!(
                "runtime call `{}` has no overload matching lowered routine `{routine_key}`",
                callable.join(".")
            )),
            [index] => Ok(Some(*index)),
            _ => Err(format!(
                "runtime call `{}` remains ambiguous for lowered routine `{routine_key}`",
                callable.join(".")
            )),
        };
    }
    if dynamic_dispatch.is_none() && candidates.len() == 1 && !bare_receiver_lookup {
        return Ok(candidates.into_iter().next());
    }
    if !allow_receiver_root_fallback && dynamic_dispatch.is_none() {
        return Err(format!(
            "runtime call `{}` is ambiguous without lowered routine identity",
            callable.join(".")
        ));
    }
    let Some(receiver) = call_args.first().map(|arg| &arg.value) else {
        return Err(format!(
            "runtime call `{}` is ambiguous with no receiver type information",
            callable.join(".")
        ));
    };
    let receiver_type = state
        .and_then(|state| runtime_value_type(receiver, state))
        .or_else(|| runtime_value_type_without_state(receiver));
    let Some(receiver_root) = receiver_type
        .as_ref()
        .and_then(IrRoutineType::root_name)
        .map(str::to_string)
        .or_else(|| runtime_value_type_root(receiver))
    else {
        return Err(format!(
            "runtime call `{}` is ambiguous with no receiver type information",
            callable.join(".")
        ));
    };
    let filtered = candidates
        .into_iter()
        .filter(|index| {
            plan.routines
                .get(*index)
                .map(|routine| {
                    let declared = routine
                        .impl_target_type
                        .as_ref()
                        .or_else(|| routine.params.first().map(|param| &param.ty));
                    let Some(declared) = declared else {
                        return false;
                    };
                    receiver_type
                        .as_ref()
                        .map(|actual| {
                            runtime_receiver_matches_declared_type(
                                plan,
                                declared,
                                actual,
                                &routine.type_params,
                                &receiver_root,
                            )
                        })
                        .unwrap_or_else(|| declared.root_name() == Some(receiver_root.as_str()))
                })
                .unwrap_or(false)
        })
        .collect::<Vec<_>>();
    match filtered.as_slice() {
        [] => Err(format!(
            "runtime call `{}` has no overload matching receiver `{receiver_root}`",
            callable.join(".")
        )),
        [index] => Ok(Some(*index)),
        _ => Err(format!(
            "runtime call `{}` remains ambiguous for receiver `{receiver_root}`",
            callable.join(".")
        )),
    }
}

fn resolve_cleanup_footer_handler_callable_path(
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    handler_path: &[String],
) -> Vec<String> {
    let Some((first, suffix)) = handler_path.split_first() else {
        return Vec::new();
    };
    if let Some(prefix) = plan
        .module_aliases
        .get(&module_alias_scope_key(
            current_package_id,
            current_module_id,
        ))
        .and_then(|aliases| aliases.get(first))
    {
        let mut callable = prefix.clone();
        callable.extend(suffix.iter().cloned());
        return callable;
    }
    handler_path.to_vec()
}

fn cleanup_footer_return_type_is_valid(return_type: Option<&IrRoutineType>) -> bool {
    let Some(return_type) = return_type else {
        return false;
    };
    let IrRoutineTypeKind::Apply { base, args } = &return_type.kind else {
        return false;
    };
    if base.root_name() != Some("Result") || args.len() != 2 {
        return false;
    }
    matches!(
        (&args[0].kind, &args[1].kind),
        (
            IrRoutineTypeKind::Path(unit_path),
            IrRoutineTypeKind::Path(str_path),
        ) if unit_path.root_name() == Some("Unit") && str_path.root_name() == Some("Str")
    )
}

fn validate_cleanup_footer_handler_routine_plan(
    routine: &RuntimeRoutinePlan,
    handler_label: &str,
) -> Result<(), String> {
    if routine.is_async {
        return Err(format!(
            "cleanup footer handler `{handler_label}` cannot be async in v1"
        ));
    }
    if routine.params.len() != 1 {
        return Err(format!(
            "cleanup footer handler `{handler_label}` must accept exactly one parameter in v1"
        ));
    }
    if routine.params[0].mode.as_deref() != Some("take") {
        return Err(format!(
            "cleanup footer handler `{handler_label}` must take its target parameter in v1"
        ));
    }
    if !cleanup_footer_return_type_is_valid(routine.return_type.as_ref()) {
        return Err(format!(
            "cleanup footer handler `{handler_label}` must return `Result[Unit, Str]` in v1"
        ));
    }
    Ok(())
}

fn validate_runtime_cleanup_footer_handler(
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    cleanup_footer: &ParsedCleanupFooter,
) -> Result<Vec<String>, String> {
    if cleanup_footer.handler_path == [String::from("cleanup")]
        && let Some(routine_key) = cleanup_footer.resolved_routine.as_deref()
    {
        let routine = plan
            .routines
            .iter()
            .find(|routine| routine.routine_key == routine_key)
            .ok_or_else(|| {
                format!(
                    "cleanup footer handler `cleanup` resolved to missing routine `{routine_key}`"
                )
            })?;
        validate_cleanup_footer_handler_routine_plan(routine, "cleanup")?;
        return Ok(cleanup_footer.handler_path.clone());
    }
    let handler_path = &cleanup_footer.handler_path;
    let callable = resolve_cleanup_footer_handler_callable_path(
        plan,
        current_package_id,
        current_module_id,
        handler_path,
    );
    if let Some(routine_index) =
        resolve_routine_index(plan, current_package_id, current_module_id, &callable)
    {
        let routine = plan.routines.get(routine_index).ok_or_else(|| {
            format!(
                "cleanup footer handler `{}` resolved to invalid routine index `{routine_index}`",
                handler_path.join(".")
            )
        })?;
        validate_cleanup_footer_handler_routine_plan(routine, &handler_path.join("."))?;
        return Ok(callable);
    }
    Err(format!(
        "cleanup footer handler `{}` does not resolve to a callable path",
        handler_path.join(".")
    ))
}

fn execute_call_by_path(
    callable: &[String],
    resolved_routine: Option<&str>,
    dynamic_dispatch: Option<&ParsedDynamicDispatch>,
    current_package_id: &str,
    current_module_id: &str,
    type_args: Vec<String>,
    call_args: Vec<RuntimeCallArg>,
    allow_receiver_root_fallback: bool,
    plan: &RuntimePackagePlan,
    scopes: &mut Vec<RuntimeScope>,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
    allow_async: bool,
) -> RuntimeEvalResult<RuntimeValue> {
    if let Some(value) = try_execute_arcana_owned_api_call(
        callable,
        &call_args,
        scopes,
        plan,
        current_package_id,
        current_module_id,
        &BTreeMap::new(),
        &BTreeMap::new(),
        state,
        host,
    )? {
        return Ok(value);
    }
    if let Some(routine_index) = resolve_routine_index_for_call(
        plan,
        current_package_id,
        current_module_id,
        callable,
        &call_args,
        resolved_routine,
        dynamic_dispatch,
        allow_receiver_root_fallback,
        Some(state),
    )? {
        let routine = plan
            .routines
            .get(routine_index)
            .ok_or_else(|| format!("invalid routine index `{routine_index}`"))?;
        let bound_args = bind_call_args_for_routine(routine, call_args)?;
        consume_take_bound_args(scopes, routine, &bound_args)?;
        let held_locals = reserve_hold_bound_args(scopes, routine, &bound_args)?;
        let values = bound_args
            .iter()
            .map(|arg| arg.value.clone())
            .collect::<Vec<_>>();
        let execution_args = routine
            .params
            .iter()
            .zip(bound_args.iter())
            .map(|(param, arg)| runtime_execution_arg_for_bound_param(scopes, state, param, arg))
            .collect::<Vec<_>>();
        let outcome = (|| -> RuntimeEvalResult<RoutineExecutionOutcome> {
            if let Some(intrinsic_impl) = &routine.intrinsic_impl {
                let intrinsic =
                    resolve_runtime_intrinsic_impl(intrinsic_impl).ok_or_else(|| {
                        format!(
                            "unsupported runtime intrinsic `{intrinsic_impl}` for `{}`",
                            routine.symbol_name
                        )
                    })?;
                let mut final_args = values;
                let value = execute_runtime_intrinsic(
                    intrinsic,
                    &type_args,
                    &mut final_args,
                    plan,
                    Some(scopes),
                    Some(current_package_id),
                    Some(current_module_id),
                    Some(&BTreeMap::new()),
                    Some(&BTreeMap::new()),
                    state,
                    host,
                )?;
                Ok(RoutineExecutionOutcome {
                    value,
                    final_args,
                    control: None,
                })
            } else if let Some(native_impl) = &routine.native_impl {
                execute_runtime_native_binding_import(plan, routine, native_impl, &values, host)
                    .map_err(RuntimeEvalSignal::from)
            } else {
                execute_routine_call_with_state(
                    plan,
                    routine_index,
                    type_args,
                    execution_args,
                    &collect_active_owner_keys_from_scopes(scopes),
                    None,
                    None,
                    None,
                    None,
                    None,
                    state,
                    host,
                    allow_async,
                )
            }
        })();
        release_reserved_hold_locals(scopes, &held_locals);
        let outcome = outcome?;
        write_back_bound_args(
            scopes,
            plan,
            current_package_id,
            current_module_id,
            &BTreeMap::new(),
            &BTreeMap::new(),
            state,
            routine,
            &bound_args,
            &outcome.final_args,
            host,
        )?;
        if let Some(FlowSignal::OwnerExit {
            owner_key,
            exit_name,
        }) = outcome.control
        {
            return Err(RuntimeEvalSignal::OwnerExit {
                owner_key,
                exit_name,
            });
        }
        return Ok(outcome.value);
    }
    let intrinsic = resolve_runtime_intrinsic_path(callable)
        .ok_or_else(|| format!("unsupported runtime callable `{}`", callable.join(".")))?;
    let call_args = bind_call_args_for_intrinsic(callable, call_args)?;
    consume_take_call_args(scopes, intrinsic_take_arg_indices(intrinsic), &call_args)?;
    let mut values = call_args
        .iter()
        .map(|arg| arg.value.clone())
        .collect::<Vec<_>>();
    let value = execute_runtime_intrinsic(
        intrinsic,
        &type_args,
        &mut values,
        plan,
        Some(scopes),
        Some(current_package_id),
        Some(current_module_id),
        Some(&BTreeMap::new()),
        Some(&BTreeMap::new()),
        state,
        host,
    )?;
    write_back_call_args(
        scopes,
        plan,
        current_package_id,
        current_module_id,
        &BTreeMap::new(),
        &BTreeMap::new(),
        state,
        intrinsic_edit_arg_indices(intrinsic),
        &call_args,
        &values,
        host,
    )?;
    Ok(value)
}

fn execute_runtime_apply_phrase(
    subject: &ParsedExpr,
    args: &[ParsedPhraseArg],
    attached: &[ParsedHeaderAttachment],
    qualifier_type_args: &[String],
    resolved_callable: Option<&[String]>,
    resolved_routine: Option<&str>,
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
    allow_async: bool,
) -> RuntimeEvalResult<RuntimeValue> {
    let callable = resolved_callable
        .map(|path| path.to_vec())
        .or_else(|| resolve_callable_path(subject, aliases))
        .ok_or_else(|| format!("unsupported runtime callable `{subject:?}`"))?;
    let type_args = if qualifier_type_args.is_empty() {
        resolve_runtime_type_args(&extract_generic_type_args(subject), type_bindings)
    } else {
        qualifier_type_args.to_vec()
    };
    if let Some(value) = try_execute_builtin_numeric_conversion(
        &callable,
        args,
        attached,
        plan,
        current_package_id,
        current_module_id,
        scopes,
        aliases,
        type_bindings,
        state,
        host,
    )? {
        return Ok(value);
    }
    if resolve_routine_index(plan, current_package_id, current_module_id, &callable).is_none()
        && resolve_runtime_intrinsic_path(&callable).is_none()
    {
        if let Some(record) = try_construct_record_value(
            &callable,
            &type_args,
            args,
            attached,
            plan,
            current_package_id,
            current_module_id,
            scopes,
            aliases,
            type_bindings,
            state,
            host,
        )? {
            return Ok(record);
        }
        if let Some(variant) = try_construct_variant_value(
            &callable,
            args,
            attached,
            plan,
            current_package_id,
            current_module_id,
            scopes,
            aliases,
            type_bindings,
            state,
            host,
        )? {
            return Ok(variant);
        }
        if let Some(array) = try_construct_array_value(
            &callable,
            args,
            attached,
            plan,
            current_package_id,
            current_module_id,
            scopes,
            aliases,
            type_bindings,
            state,
            host,
        )? {
            return Ok(array);
        }
        return Err(format!("unsupported runtime callable `{}`", callable.join(".")).into());
    }
    let call_args = collect_call_args(
        args,
        attached,
        plan,
        current_package_id,
        current_module_id,
        scopes,
        aliases,
        type_bindings,
        state,
        host,
    )?;
    execute_call_by_path(
        &callable,
        resolved_routine,
        None,
        current_package_id,
        current_module_id,
        type_args,
        call_args,
        false,
        plan,
        scopes,
        state,
        host,
        allow_async,
    )
}

fn execute_runtime_method_call_with_type_args(
    subject: &ParsedExpr,
    args: &[ParsedPhraseArg],
    attached: &[ParsedHeaderAttachment],
    qualifier: &str,
    qualifier_type_args: &[String],
    resolved_callable: Option<&[String]>,
    resolved_routine: Option<&str>,
    dynamic_dispatch: Option<&ParsedDynamicDispatch>,
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> RuntimeEvalResult<RuntimeValue> {
    let receiver = read_runtime_value_if_ref(
        eval_expr(
            subject,
            plan,
            current_package_id,
            current_module_id,
            scopes,
            aliases,
            type_bindings,
            state,
            host,
        )?,
        scopes,
        plan,
        current_package_id,
        current_module_id,
        aliases,
        type_bindings,
        state,
        host,
    )?;
    let callable = resolved_callable
        .map(|callable| callable.to_vec())
        .unwrap_or_else(|| vec![qualifier.to_string()]);
    let type_args = if qualifier_type_args.is_empty() {
        runtime_receiver_type_args(&receiver, state)
    } else {
        qualifier_type_args.to_vec()
    };
    let mut call_args = vec![RuntimeCallArg {
        name: None,
        value: receiver,
        source_expr: subject.clone(),
    }];
    call_args.extend(collect_call_args(
        args,
        attached,
        plan,
        current_package_id,
        current_module_id,
        scopes,
        aliases,
        type_bindings,
        state,
        host,
    )?);
    execute_call_by_path(
        &callable,
        resolved_routine,
        dynamic_dispatch,
        current_package_id,
        current_module_id,
        type_args,
        call_args,
        resolved_routine.is_none(),
        plan,
        scopes,
        state,
        host,
        runtime_async_calls_allowed(state),
    )
}

fn execute_runtime_named_qualifier_call(
    subject: &ParsedExpr,
    args: &[ParsedPhraseArg],
    attached: &[ParsedHeaderAttachment],
    qualifier: &str,
    qualifier_type_args: &[String],
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> RuntimeEvalResult<RuntimeValue> {
    let receiver = read_runtime_value_if_ref(
        eval_expr(
            subject,
            plan,
            current_package_id,
            current_module_id,
            scopes,
            aliases,
            type_bindings,
            state,
            host,
        )?,
        scopes,
        plan,
        current_package_id,
        current_module_id,
        aliases,
        type_bindings,
        state,
        host,
    )?;
    let callable_expr = parse_runtime_callable_expr(qualifier);
    let callable = resolve_named_qualifier_callable_path(&callable_expr, aliases)
        .ok_or_else(|| format!("unsupported runtime named qualifier callable `{qualifier}`"))?;
    let type_args = if qualifier_type_args.is_empty() {
        resolve_runtime_type_args(&extract_generic_type_args(&callable_expr), type_bindings)
    } else {
        qualifier_type_args.to_vec()
    };
    let mut call_args = vec![RuntimeCallArg {
        name: None,
        value: receiver,
        source_expr: subject.clone(),
    }];
    call_args.extend(collect_call_args(
        args,
        attached,
        plan,
        current_package_id,
        current_module_id,
        scopes,
        aliases,
        type_bindings,
        state,
        host,
    )?);
    execute_call_by_path(
        &callable,
        None,
        None,
        current_package_id,
        current_module_id,
        type_args,
        call_args,
        false,
        plan,
        scopes,
        state,
        host,
        runtime_async_calls_allowed(state),
    )
}

fn eval_qualifier(
    subject: &ParsedExpr,
    args: &[ParsedPhraseArg],
    attached: &[ParsedHeaderAttachment],
    qualifier: &str,
    qualifier_type_args: &[String],
    resolved_callable: Option<&[String]>,
    resolved_routine: Option<&str>,
    dynamic_dispatch: Option<&ParsedDynamicDispatch>,
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> RuntimeEvalResult<RuntimeValue> {
    execute_runtime_method_call_with_type_args(
        subject,
        args,
        attached,
        qualifier,
        qualifier_type_args,
        resolved_callable,
        resolved_routine,
        dynamic_dispatch,
        plan,
        current_package_id,
        current_module_id,
        scopes,
        aliases,
        type_bindings,
        state,
        host,
    )
}

fn try_unwrap_runtime_result(value: RuntimeValue) -> RuntimeEvalResult<RuntimeValue> {
    match value {
        RuntimeValue::Variant { name, payload } if variant_name_matches(&name, "Result.Ok") => {
            match payload.as_slice() {
                [value] => Ok(value.clone()),
                _ => Err(format!(
                    "runtime try qualifier `?` expected Result.Ok with one payload value, got `{name}`"
                )
                .into()),
            }
        }
        RuntimeValue::Variant { ref name, .. } if variant_name_matches(name, "Result.Err") => {
            Err(RuntimeEvalSignal::Return(value))
        }
        other => Err(format!(
            "runtime try qualifier `?` expects Result-shape value, got `{other:?}`"
        )
        .into()),
    }
}

fn eval_try_qualifier(
    subject: &ParsedExpr,
    args: &[ParsedPhraseArg],
    attached: &[ParsedHeaderAttachment],
    plan: &RuntimePackagePlan,
    current_package_id: &str,
    current_module_id: &str,
    scopes: &mut Vec<RuntimeScope>,
    aliases: &BTreeMap<String, Vec<String>>,
    type_bindings: &RuntimeTypeBindings,
    state: &mut RuntimeExecutionState,
    host: &mut dyn RuntimeHost,
) -> RuntimeEvalResult<RuntimeValue> {
    if !args.is_empty() {
        return Err("`:: ?` does not accept arguments".to_string().into());
    }
    if !attached.is_empty() {
        return Err("`:: ?` does not support an attached block"
            .to_string()
            .into());
    }
    try_unwrap_runtime_result(eval_expr(
        subject,
        plan,
        current_package_id,
        current_module_id,
        scopes,
        aliases,
        type_bindings,
        state,
        host,
    )?)
}

