            | RuntimeIntrinsic::WindowId
            | RuntimeIntrinsic::WindowPosition
            | RuntimeIntrinsic::WindowTitle
            | RuntimeIntrinsic::WindowVisible
            | RuntimeIntrinsic::WindowDecorated
